def assess(record: dict) -> str:
    required_fields = {"case_id", "method", "resource", "created", "status"}
    absent = sorted(required_fields - set(record))
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = record["method"] == "POST" and record["status"] == 201
    return "PASS" if ok else "RETURN_CORRECT_HTTP_STATUS"

valid = {"case_id": "CASO-ARE-041-1A", **{"method": "POST", "resource": "/v1/jobs", "created": True, "status": 201}}
invalid = {"case_id": "CASO-ARE-041-1A", **{"method": "", "resource": "/v1/jobs", "created": True, "status": 201}}
incomplete = dict(valid)
if "status" in incomplete:
    del incomplete["status"]
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

